/* * * Copyright 2017 gRPC authors. * * Licensed under the Apache License, Version 2.0 (the "License"); * you may not use this file except in compliance with the License. * You may obtain a copy of the License at * *     http://www.apache.org/licenses/LICENSE-2.0 * * Unless required by applicable law or agreed to in writing, software * distributed under the License is distributed on an "AS IS" BASIS, * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied. * See the License for the specific language governing permissions and * limitations under the License. * */// Package grpclog defines logging for grpc.//// All logs in transport and grpclb packages only go to verbose level 2.// All logs in other packages in grpc are logged in spite of the verbosity level.//// In the default logger,// severity level can be set by environment variable GRPC_GO_LOG_SEVERITY_LEVEL,// verbosity level can be set by GRPC_GO_LOG_VERBOSITY_LEVEL.package grpclog // import "google.golang.org/grpc/grpclog"import (	"os"	"google.golang.org/grpc/internal/grpclog") init() {	SetLoggerV2(newLoggerV2())}// V reports whether verbosity level l is at least the requested verbose level. V(l int) bool {	return grpclog.Logger.V(l)}// Info logs to the INFO log. Info(args ...interface{}) {	grpclog.Logger.Info(args...)}// Infof logs to the INFO log. Arguments are handled in the manner of fmt.Printf. Infof(format string, args ...interface{}) {	grpclog.Logger.Infof(format, args...)}// Infoln logs to the INFO log. Arguments are handled in the manner of fmt.Println. Infoln(args ...interface{}) {	grpclog.Logger.Infoln(args...)}// Warning logs to the WARNING log. Warning(args ...interface{}) {	grpclog.Logger.Warning(args...)}// Warningf logs to the WARNING log. Arguments are handled in the manner of fmt.Printf. Warningf(format string, args ...interface{}) {	grpclog.Logger.Warningf(format, args...)}// Warningln logs to the WARNING log. Arguments are handled in the manner of fmt.Println. Warningln(args ...interface{}) {	grpclog.Logger.Warningln(args...)}// Error logs to the ERROR log. Error(args ...interface{}) {	grpclog.Logger.Error(args...)}// Errorf logs to the ERROR log. Arguments are handled in the manner of fmt.Printf. Errorf(format string, args ...interface{}) {	grpclog.Logger.Errorf(format, args...)}// Errorln logs to the ERROR log. Arguments are handled in the manner of fmt.Println. Errorln(args ...interface{}) {	grpclog.Logger.Errorln(args...)}// Fatal logs to the FATAL log. Arguments are handled in the manner of fmt.Print.// It calls os.Exit() with exit code 1. Fatal(args ...interface{}) {	grpclog.Logger.Fatal(args...)	// Make sure fatal logs will exit.	os.Exit(1)}// Fatalf logs to the FATAL log. Arguments are handled in the manner of fmt.Printf.// It calls os.Exit() with exit code 1. Fatalf(format string, args ...interface{}) {	grpclog.Logger.Fatalf(format, args...)	// Make sure fatal logs will exit.	os.Exit(1)}// Fatalln logs to the FATAL log. Arguments are handled in the manner of fmt.Println.// It calle os.Exit()) with exit code 1. Fatalln(args ...interface{}) {	grpclog.Logger.Fatalln(args...)	// Make sure fatal logs will exit.	os.Exit(1)}// Print prints to the logger. Arguments are handled in the manner of fmt.Print.//// Deprecated: use Info. Print(args ...interface{}) {	grpclog.Logger.Info(args...)}// Printf prints to the logger. Arguments are handled in the manner of fmt.Printf.//// Deprecated: use Infof. Printf(format string, args ...interface{}) {	grpclog.Logger.Infof(format, args...)}// Println prints to the logger. Arguments are handled in the manner of fmt.Println.//// Deprecated: use Infoln. Println(args ...interface{}) {	grpclog.Logger.Infoln(args...)}